async function fetchUser(id: string, retries: number = 3): Promise<User | null> {
  for (let i = 0; i < retries; i++) {
    try {
      const res = await fetch(`/api/users/${id}`);
      if (res.ok) return await res.json();
    } catch (e) {
      if (i === retries - 1) throw e;
    }
  }
  return null;
}
